import React, { type FunctionComponent, type PropsWithChildren, type ReactNode } from "react";
import {Box, Flex, Heading} from "../../_compat";
import type { IFlexComponent } from "@lmb-it/kitsconcerto-types";

export interface IContainerProps extends IFlexComponent {
    title?: ReactNode | string;
    rightElement?: ReactNode | string;
    childrenContainerProps?: IFlexComponent;
}

const Container: FunctionComponent<PropsWithChildren<IContainerProps>> = ({
                                                                              title,
                                                                              rightElement,
                                                                              children,
                                                                              childrenContainerProps = {},
                                                                              ...props
                                                                          }) => {
    return (
        <Box
            bgColor={"surface-card"}
            borderRadius={8}
            w={"full"}
            overflow="hidden"
            marginBottom={8}
            shadow="md"
            {...props}
        >
            {(!!title || !!rightElement) && (
                <Flex
                    bgColor={"surface-hover"}
                    borderRadiusTop={8}
                    p={10}
                    flexDirection={"row"}
                    alignItems={"center"}
                    h={58}
                    justifyContent={"space-between"}
                >
                    {!!title && (
                        <Heading
                            as={"h2"}
                            fontSize={"lg"}
                            fontWeight={"bold"}
                            fontColor={"text"}
                            letterSpacing={0}
                            fontFamily={"Poppins,Helvetica,sans-serif"}
                            margin={0}
                            padding={0}
                        >
                            {title}
                        </Heading>
                    )}

                    {rightElement}
                </Flex>
            )}
            <Flex
                p={10}
                flex={1}
                flexDirection={"column"}
                {...childrenContainerProps}
            >
                {children}
            </Flex>
        </Box>
    );
};

export default Container;
